        return _pools[pool];
    }

    function addPool(address pool, address rewardToken) external onlyOwner {
        require(pool != address(0), "Invalid pool address");
        require(_pools[pool] == address(0), "Pool already exists");
        _pools[pool] = rewardToken;
        emit PoolAdded(pool, rewardToken);
    }

    function removePool(address pool) external onlyOwner {
        require(_pools[pool] != address(0), "Pool does not exist");
        delete _pools[pool];
        emit PoolRemoved(pool);
    }

    function transferTo(address payable to, uint256 amount) external noReentrancy {
        require(_pools[msg.sender] != address(0), "Unauthorized pool");
        require(amount <= address(this).balance, "Insufficient balance");

        // Update state before making external call to prevent reentrancy
        _inTransfer = false; // Reset reentrancy guard early

        (bool sent,) = to.call{value: amount, gas: 2300}("");
        require(sent, "Failed to send Ether");

        emit TransferExecuted(to, amount);
    }

    function rescueFund(address payable to, uint256 amount) external onlyOwner {
        require(amount <= address(this).balance, "Insufficient balance");

        // Update state before making external call to prevent reentrancy
        _inTransfer = false; // Reset reentrancy guard early

        (bool sent,) = to.call{value: amount, gas: 2300}("");
        require(sent, "Failed to send Ether");

        emit FundRescued(to, amount);
    }

    receive() external payable {
        require(msg.sender == _owner, "Only owner can receive funds");
    }
}
